import React, { Component } from "react";

class Tools extends Component {
  toolsList = [
    {
      id: 1,
      frontEnd: ["JavaScript", "Angular", "ReactJS", "SASS", "HTML5"],
      backEnd: ["PHP", "MySQL", "ExpressJS"],
      tools: [
        "npm",
        "Git",
        "Bitbucket",
        "Jira",
        "Confluence",
        "NodeJS",
        "APIs",
        "Docker",
        "MongoDB",
        "Adobe CC",
        "FIgma",
      ],
    },
  ];
  render() {
    return (
      <div className="about-container">
        <div className="row">
          {this.toolsList.map(({ id, frontEnd, backEnd, toString }, i) => (
            <div key={i} className="col-md-3">
              <h4>Front End</h4>
              {frontEnd.map((x, j) => (
                <p key={j}>{x}</p>
              ))}
            </div>
          ))}
        </div>
      </div>
    );
  }
}

export default Tools;
